server/storage.ts.content:
import { eq, desc, and, gt, inArray } from "drizzle-orm";
import { db } from "./db";
import { 
  users, 
  quizzes, 
  quizResults,
  quizComments,
  quizVotes,
  quizProgress,
  verificationTokens,
  type User, 
  type UpsertUser, 
  type Quiz, 
  type QuizResult,
  type QuizComment,
  type QuizVote,
  type QuizProgress,
  type InsertQuiz,
  type InsertQuizResult,
  type InsertComment,
  type InsertVote,
  type InsertQuizProgress,
  type Question,
  type VerificationToken
} from "@shared/schema";

export interface IStorage {
  getUser(id: string): Promise<User | undefined>;
  getUserByEmail(email: string): Promise<User | undefined>;
  getUserByGoogleId(googleId: string): Promise<User | undefined>;
  upsertUser(user: UpsertUser): Promise<User>;
  createUser(user: Omit<UpsertUser, "id">): Promise<User>;
  updateUser(id: string, updates: Partial<UpsertUser>): Promise<User | undefined>;
  createVerificationToken(userId: string, token: string, type: string, expiresAt: Date): Promise<VerificationToken>;
  getVerificationToken(token: string): Promise<VerificationToken | undefined>;
  deleteVerificationToken(token: string): Promise<void>;
  verifyUserEmail(userId: string): Promise<void>;
