  async getUserVote(quizId: string, userId: string): Promise<number | null> {
    const [vote] = await db.select()
      .from(quizVotes)
      .where(and(eq(quizVotes.quizId, quizId), eq(quizVotes.userId, userId)));
    return vote?.voteType || null;
  }

  async getUserStreak(userId: string): Promise<{ 
    currentStreak: number; 
    longestStreak: number; 
    lastActivityDate: string | null; 
    isActive: boolean;
    isFirstCompletionToday: boolean;
  }> {
    // Get quiz completion dates for quizzes with more than 8 questions only
    const userQuizIds = await db.select({ id: quizzes.id })
      .from(quizzes)
      .where(eq(quizzes.userId, userId));

    let completionDates: Date[] = [];
    if (userQuizIds.length > 0) {
      const quizIdList = userQuizIds.map(q => q.id);
      // Only count completions of quizzes with more than 8 questions
      const results = await db.select({ completedAt: quizResults.completedAt, totalQuestions: quizResults.totalQuestions })
        .from(quizResults)
        .where(inArray(quizResults.quizId, quizIdList));
      completionDates = results
        .filter(r => r.totalQuestions > 8)
        .map(r => r.completedAt);
    }

    // Only count quiz completions (not creations) for streak
    const allDates = completionDates.filter(Boolean) as Date[];

    if (allDates.length === 0) {
      return { 
        currentStreak: 0, 
        longestStreak: 0, 
        lastActivityDate: null, 
        isActive: false,
        isFirstCompletionToday: false
      };
    }

    // Convert to unique date strings (YYYY-MM-DD)
    const dateStrings = allDates.map(d => {
      const date = new Date(d);
      return date.toISOString().split('T')[0];
    });
    const uniqueDays = Array.from(new Set(dateStrings)).sort().reverse();

    if (uniqueDays.length === 0) {
      return { 
        currentStreak: 0, 
        longestStreak: 0, 
        lastActivityDate: null, 
        isActive: false,
        isFirstCompletionToday: false
      };
    }

    const lastActivityDate = uniqueDays[0];
    const today = new Date().toISOString().split('T')[0];
    const yesterday = new Date(Date.now() - 86400000).toISOString().split('T')[0];

    // Calculate current streak
    let currentStreak = 0;
    let checkDate = today;
    const isActive = uniqueDays.includes(today);

    // Calculate completions specifically for today to determine if this is the first one
    // Note: The streak calculation uses both quiz creation and completions.
    // The user specifically asked for "one quiz completion only".
    const todayCompletions = completionDates.filter(d => 
      new Date(d).toISOString().split('T')[0] === today
    ).length;

    // Check if there's activity today or yesterday to start the streak
    if (uniqueDays.includes(today)) {
      currentStreak = 1;
      checkDate = new Date(Date.now() - 86400000).toISOString().split('T')[0];
    } else if (uniqueDays.includes(yesterday)) {
      currentStreak = 1;
      checkDate = new Date(Date.now() - 2 * 86400000).toISOString().split('T')[0];
    } else {
      // No recent activity, streak is 0
      return { 
        currentStreak: 0, 
        longestStreak: this.calculateLongestStreak(uniqueDays), 
        lastActivityDate, 
        isActive: false,
        isFirstCompletionToday: false
      };
    }

    // Count consecutive days backwards
    while (uniqueDays.includes(checkDate)) {
      currentStreak++;
      const nextDate = new Date(new Date(checkDate).getTime() - 86400000);
      checkDate = nextDate.toISOString().split('T')[0];
    }

    const longestStreak = Math.max(currentStreak, this.calculateLongestStreak(uniqueDays));

    return { 
      currentStreak, 
      longestStreak, 
      lastActivityDate, 
      isActive,
      isFirstCompletionToday: todayCompletions === 1 && isActive
    };
  }

  async getUserStreakHistory(userId: string): Promise<string[]> {
    // Get quiz completion dates for quizzes with more than 8 questions only
    const userQuizIds = await db.select({ id: quizzes.id })
      .from(quizzes)
      .where(eq(quizzes.userId, userId));

    let completionDates: Date[] = [];
    if (userQuizIds.length > 0) {
      const quizIdList = userQuizIds.map(q => q.id);
      // Only count completions of quizzes with more than 8 questions
      const results = await db.select({ completedAt: quizResults.completedAt, totalQuestions: quizResults.totalQuestions })
        .from(quizResults)
        .where(inArray(quizResults.quizId, quizIdList));
      completionDates = results
        .filter(r => r.totalQuestions > 8)
        .map(r => r.completedAt);
    }

    // Only count quiz completions (not creations) for streak
    const allDates = completionDates.filter(Boolean) as Date[];

    // Convert to unique date strings (YYYY-MM-DD) and return sorted
    const dateStrings = allDates.map(d => {
      const date = new Date(d);
      return date.toISOString().split('T')[0];
    });
    return Array.from(new Set(dateStrings)).sort();
  }

  async getUsersForStreakReminder(): Promise<User[]> {
    const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);

    // Get all users who:
    // 1. Have verified emails
    // 2. Have streak reminders enabled
    // 3. Haven't received a reminder in the last 24 hours (or never received one)
    const eligibleUsers = await db
      .select()
      .from(users)
      .where(
        and(
          eq(users.emailVerified, true),
          eq(users.streakReminderEnabled, true)
        )
      );

    // Filter users who haven't received reminder in 24h
    return eligibleUsers.filter(user => {
      if (!user.lastStreakReminderSentAt) return true;
      return new Date(user.lastStreakReminderSentAt) < oneDayAgo;
    });
  }

  async updateLastStreakReminderSentAt(userId: string): Promise<void> {
    await db
      .update(users)
      .set({ lastStreakReminderSentAt: new Date(), updatedAt: new Date() })
      .where(eq(users.id, userId));
  }

  private calculateLongestStreak(sortedDaysDesc: string[]): number {
    if (sortedDaysDesc.length === 0) return 0;

    const sortedDays = [...sortedDaysDesc].sort();
    let longestStreak = 1;
    let currentRun = 1;

    for (let i = 1; i < sortedDays.length; i++) {
      const prevDate = new Date(sortedDays[i - 1]);
      const currDate = new Date(sortedDays[i]);
      const diffDays = (currDate.getTime() - prevDate.getTime()) / 86400000;

      if (diffDays === 1) {
        currentRun++;
        longestStreak = Math.max(longestStreak, currentRun);
      } else if (diffDays > 1) {
        currentRun = 1;
      }
    }

    return longestStreak;
  }

  async getUserRecommendationData(userId: string): Promise<{
    hasData: boolean;
    userCategories: string[];
    weakCategories: string[];
    recentQuizIds: string[];
  }> {
    // Get quizzes the user has taken (from quiz results with userId)
    const userResults = await db.select()
      .from(quizResults)
      .where(eq(quizResults.userId, userId))
      .orderBy(desc(quizResults.completedAt));

    // Also get quizzes the user has created (ordered by creation date)
    const userCreatedQuizzes = await this.getQuizzesByUserId(userId);

    // Build recentQuizIds preserving recency order from results first
    const recentTakenQuizIds: string[] = [];
    const seenIds = new Set<string>();
    for (const result of userResults) {
      if (!seenIds.has(result.quizId)) {
        recentTakenQuizIds.push(result.quizId);
        seenIds.add(result.quizId);
      }
    }

    // Add created quiz IDs
    const createdQuizIds = userCreatedQuizzes.map(q => q.id);
    for (const id of createdQuizIds) {
      if (!seenIds.has(id)) {
        seenIds.add(id);
      }
    }

    const allUserQuizIds = Array.from(seenIds);

    // User has data if they've created quizzes OR taken quizzes with tracked results
    const hasCreatedQuizzes = userCreatedQuizzes.length > 0;
    const hasTakenQuizzes = userResults.length > 0;

    if (!hasCreatedQuizzes && !hasTakenQuizzes) {
      return { hasData: false, userCategories: [], weakCategories: [], recentQuizIds: [] };
    }

    // Get quiz details for category lookup
    const quizDetails = await db.select()
      .from(quizzes)
      .where(inArray(quizzes.id, allUserQuizIds));

    const quizMap = new Map(quizDetails.map(q => [q.id, q]));

    // Get categories from quizzes the user has interacted with
    const userCategories = Array.from(new Set(
      quizDetails.map(q => q.category || "Others/General")
    ));

    // Calculate accuracy per category from results
    const categoryStats: Record<string, { correct: number; total: number }> = {};

    for (const result of userResults) {
      const quiz = quizMap.get(result.quizId);
      if (!quiz) continue;

      const category = quiz.category || "Others/General";
      if (!categoryStats[category]) {
        categoryStats[category] = { correct: 0, total: 0 };
      }
      categoryStats[category].correct += result.correctAnswers;
      categoryStats[category].total += result.totalQuestions;
    }

    // Find weak categories (accuracy below 70%)
    const weakCategories = Object.entries(categoryStats)
      .filter(([_, stats]) => stats.total > 0 && (stats.correct / stats.total) < 0.7)
      .map(([category]) => category);

    // Use recency-ordered quiz IDs for exclusion (taken quizzes first, then created)
    const recentQuizIds = [...recentTakenQuizIds, ...createdQuizIds.filter(id => !recentTakenQuizIds.includes(id))].slice(0, 30);

    return {
      hasData: true,
      userCategories,
      weakCategories,
      recentQuizIds,
    };
  }

  // Quiz Progress methods
  async getQuizProgressByUserId(userId: string): Promise<(QuizProgress & { quiz: Quiz })[]> {
    const results = await db
      .select({
        progress: quizProgress,
        quiz: quizzes,
      })
      .from(quizProgress)
      .innerJoin(quizzes, eq(quizProgress.quizId, quizzes.id))
      .where(eq(quizProgress.userId, userId))
      .orderBy(desc(quizProgress.savedAt));

    return results.map(r => ({
      ...r.progress,
      quiz: r.quiz,
    }));
  }

  async saveQuizProgress(progress: InsertQuizProgress): Promise<QuizProgress & { quiz: Quiz }> {
    // Upsert: delete existing progress for this user+quiz, then insert new
    await db.delete(quizProgress)
      .where(and(
        eq(quizProgress.userId, progress.userId),
        eq(quizProgress.quizId, progress.quizId)
      ));

    const [saved] = await db.insert(quizProgress)
      .values({
        userId: progress.userId,
        quizId: progress.quizId,
        answers: progress.answers,
        checkedQuestions: progress.checkedQuestions || [],
        currentIndex: progress.currentIndex ?? 0,
        retryAnswers: progress.retryAnswers ?? {},
        retryCheckedQuestions: progress.retryCheckedQuestions ?? [],
      })
      .returning();

    // Fetch the quiz to return joined data
    const quiz = await this.getQuiz(progress.quizId);
    if (!quiz) {
      throw new Error("Quiz not found");
    }

    return { ...saved, quiz };
  }

  async deleteQuizProgress(userId: string, quizId: string): Promise<boolean> {
    await db.delete(quizProgress)
      .where(and(
        eq(quizProgress.userId, userId),
        eq(quizProgress.quizId, quizId)
      ));
    return true;
  }
}

