              <stop offset="100%" stopColor="white" stopOpacity="0" />
            </linearGradient>
            <filter id="glow">
              <feGaussianBlur stdDeviation="2" result="coloredBlur"/>
              <feMerge>
                <feMergeNode in="coloredBlur"/>
                <feMergeNode in="SourceGraphic"/>
              </feMerge>
            </filter>
          </defs>

          <image 
            href={logoImage} 
            x="0" 
            y="0" 
            width="100" 
            height="100" 
            preserveAspectRatio="xMidYMid meet"
            filter="url(#glow)"
          />

          <g mask="url(#logoMask)">
            <motion.rect
              y="0"
              width="35"
              height="100"
              fill="url(#trailGradient)"
              initial={{ x: -45 }}
              animate={{ x: 145 }}
              transition={{
                duration: 1.2,
                repeat: Infinity,
                ease: "easeInOut",
              }}
            />
          </g>
        </svg>
      </motion.div>
    </div>
