import { createContext, useContext, useState, useCallback, useEffect, useRef, useMemo, type ReactNode, type MouseEvent } from "react";
import { useLocation } from "wouter";
import { useQuiz } from "@/lib/quiz-context";
import { useAuth } from "@/hooks/useAuth";
import { Save, AlertTriangle } from "lucide-react";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";

interface QuizNavigationGuardContextType {
  navigateWithGuard: (path: string) => void;
  isQuizInProgress: boolean;
  handleLinkClick: (e: MouseEvent, path: string, callback?: () => void) => void;
}

const QuizNavigationGuardContext = createContext<QuizNavigationGuardContextType | undefined>(undefined);

export function QuizNavigationGuardProvider({ children }: { children: ReactNode }) {
  const [, setLocation] = useLocation();
  const [location] = useLocation();
  const { currentQuiz, hasUnsavedChanges, saveCurrentProgress, getPlayerProgress, userAnswers, checkedQuestions, playerRetryAnswers } = useQuiz();
  const { user } = useAuth();
  const [showExitDialog, setShowExitDialog] = useState(false);
  const [pendingPath, setPendingPath] = useState<string | null>(null);
  const hasAddedHistoryEntry = useRef(false);

  // Guests cannot save progress, so skip the guard entirely
  const isGuest = !user;

  // Show dialog if user is on quiz page with an active quiz that has any answers (only for authenticated users)
  const isQuizInProgress = !isGuest && location === "/quiz" && !!currentQuiz && Object.keys(userAnswers).length > 0;

  // Check if user is in revision mode (completed first attempt with wrong answers)
  const isInRevisionMode = useMemo(() => {
    if (!currentQuiz || location !== "/quiz") return false;

    const questions = currentQuiz.questions || [];
    const totalQuestions = questions.length;
    const checkedCount = checkedQuestions.size;

    // Must have completed first attempt (all questions checked)
    const hasCompletedFirstAttempt = checkedCount >= totalQuestions && totalQuestions > 0;
    if (!hasCompletedFirstAttempt) return false;

    // Check if there are wrong answers
    let wrongCount = 0;
    for (const q of questions) {
      const userAnswer = userAnswers[q.id];
      if (userAnswer && userAnswer.toLowerCase().trim() !== q.correctAnswer.toLowerCase().trim()) {
        wrongCount++;
      }
    }

    // Check if there's any retry progress in session
    const hasRetryProgress = Object.keys(playerRetryAnswers).length > 0;

    return (hasCompletedFirstAttempt && wrongCount > 0) || hasRetryProgress;
  }, [currentQuiz, location, userAnswers, checkedQuestions, playerRetryAnswers]);

  // Handle browser back button
  useEffect(() => {
    if (isQuizInProgress && !hasAddedHistoryEntry.current) {
      // Push an extra history entry so we can intercept back button
      window.history.pushState({ quizGuard: true }, "", window.location.href);
      hasAddedHistoryEntry.current = true;
    }

    if (!isQuizInProgress) {
      hasAddedHistoryEntry.current = false;
    }

    const handlePopState = (e: PopStateEvent) => {
      if (isQuizInProgress) {
        // Re-push the history entry to prevent navigation
        window.history.pushState({ quizGuard: true }, "", window.location.href);
        // Show the dialog
        setPendingPath("/dashboard");
        setShowExitDialog(true);
      }
    };

    window.addEventListener("popstate", handlePopState);
    return () => window.removeEventListener("popstate", handlePopState);
  }, [isQuizInProgress]);

  const navigateWithGuard = useCallback((path: string) => {
    if (isQuizInProgress && path !== "/quiz" && path !== "/results") {
      setPendingPath(path);
      setShowExitDialog(true);
    } else {
      setLocation(path);
    }
  }, [isQuizInProgress, setLocation]);

  const handleLinkClick = useCallback((e: MouseEvent, path: string, callback?: () => void) => {
    if (isQuizInProgress && path !== "/quiz" && path !== "/results") {
      e.preventDefault();
      setPendingPath(path);
      setShowExitDialog(true);
    } else {
      callback?.();
    }
  }, [isQuizInProgress]);

  const handleSaveAndExit = () => {
    // Pass explicit player progress to ensure revision state is saved correctly
    saveCurrentProgress(getPlayerProgress());
    setShowExitDialog(false);
    if (pendingPath) {
      setLocation(pendingPath);
      setPendingPath(null);
    }
  };

  const handleCancel = () => {
    setShowExitDialog(false);
    setPendingPath(null);
  };

  // For revision mode: save progress including revision state before exiting
  const handleExitRevision = () => {
    // Pass explicit player progress to ensure revision state is saved correctly
    saveCurrentProgress(getPlayerProgress());
    setShowExitDialog(false);
    if (pendingPath) {
      setLocation(pendingPath);
      setPendingPath(null);
    }
  };

  return (
    <QuizNavigationGuardContext.Provider value={{ navigateWithGuard, isQuizInProgress, handleLinkClick }}>
      {children}
      <AlertDialog open={showExitDialog} onOpenChange={(open) => !open && handleCancel()}>
        <AlertDialogContent data-testid={isInRevisionMode ? "dialog-revision-exit-warning" : "dialog-quiz-exit"}>
          <AlertDialogHeader>
            <AlertDialogTitle className="flex items-center gap-2">
              {isInRevisionMode ? "Save Revision Progress?" : "Leave Quiz?"}
            </AlertDialogTitle>
            <AlertDialogDescription>
              {isInRevisionMode 
                ? "You're currently revising incorrect answers. Your revision progress will be saved so you can continue later."
                : "You have a quiz in progress. Would you like to save your progress for later?"
              }
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter className="flex-col sm:flex-row gap-2">
            <AlertDialogCancel onClick={handleCancel} data-testid="button-cancel-nav-exit">
              {isInRevisionMode ? "Keep Revising" : "Continue Quiz"}
            </AlertDialogCancel>
            <AlertDialogAction
              onClick={isInRevisionMode ? handleExitRevision : handleSaveAndExit}
              className="gap-2"
              data-testid={isInRevisionMode ? "button-confirm-revision-exit" : "button-save-nav-exit"}
            >
              <Save className="h-4 w-4" />
              Save & Exit
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </QuizNavigationGuardContext.Provider>
  );
}

export function useQuizNavigationGuard() {
  const context = useContext(QuizNavigationGuardContext);
  if (!context) {
    throw new Error("useQuizNavigationGuard must be used within QuizNavigationGuardProvider");
  }
  return context;
}

server/upload-jobs.ts.content:
import { createWorker } from "tesseract.js";
import * as pdfjsLib from "pdfjs-dist/legacy/build/pdf.mjs";
import { parseOffice } from "officeparser";
import JSZip from "jszip";

export interface UploadJob {
  id: string;
  status: "pending" | "processing" | "completed" | "error";
  progress: number;
  message: string;
  text?: string;
  error?: string;
  fileType: string;
  createdAt: Date;
  isOfficeWithImages?: boolean;
  documentImages?: string[];
  isImageOnly?: boolean;
}

const jobs = new Map<string, UploadJob>();
const jobBuffers = new Map<string, Buffer>();

let tesseractWorker: Awaited<ReturnType<typeof createWorker>> | null = null;

async function getOCRWorker() {
  if (!tesseractWorker) {
    tesseractWorker = await createWorker("eng+vie");
  }
  return tesseractWorker;
}

export function createJob(id: string, fileType: string): UploadJob {
  const job: UploadJob = {
    id,
    status: "pending",
    progress: 0,
    message: "Queued for processing...",
    fileType,
    createdAt: new Date(),
  };
  jobs.set(id, job);
  return job;
}

export function getJob(id: string): UploadJob | undefined {
  return jobs.get(id);
}

export function updateJob(id: string, updates: Partial<UploadJob>) {
  const job = jobs.get(id);
  if (job) {
    Object.assign(job, updates);
  }
}

export function storeBuffer(id: string, buffer: Buffer) {
  jobBuffers.set(id, buffer);
}

export function cleanupBuffer(id: string) {
  jobBuffers.delete(id);
}

export function deleteJob(id: string) {
  jobs.delete(id);
  jobBuffers.delete(id);
}

async function extractTextFromPDF(buffer: Buffer): Promise<string> {
  const data = new Uint8Array(buffer);
  const loadingTask = pdfjsLib.getDocument({ data });
  const pdf = await loadingTask.promise;

  let fullText = "";

  for (let i = 1; i <= pdf.numPages; i++) {
    const page = await pdf.getPage(i);
    const content = await page.getTextContent();

    let lastY: number | null = null;
    const pageTextParts: string[] = [];

    for (const item of content.items as any[]) {
      if (item.str) {
        if (lastY !== null && Math.abs(item.transform[5] - lastY) > 5) {
          pageTextParts.push("\n");
        } else if (pageTextParts.length > 0 && !pageTextParts[pageTextParts.length - 1].endsWith(" ")) {
          pageTextParts.push(" ");
        }
        pageTextParts.push(item.str);
        lastY = item.transform[5];
      }
    }

    fullText += pageTextParts.join("") + "\n\n";
  }

  return fullText
    .replace(/\s+/g, " ")
    .replace(/\n\s*\n/g, "\n\n")
    .trim();
}

async function extractTextFromImage(buffer: Buffer): Promise<string> {
  const worker = await getOCRWorker();
  const { data: { text } } = await worker.recognize(buffer);
  return text.trim();
}

async function extractTextFromOfficeDocument(buffer: Buffer): Promise<string> {
  try {
    const result = await parseOffice(buffer);
    const text = typeof result === 'string' ? result : (result.toText ? result.toText() : String(result));
    console.log("Office parser text length:", text.length);
    console.log("Office parser text preview:", text.substring(0, 200));
    return text.trim();
  } catch (error) {
    console.error("Office parser error:", error);
    throw new Error("Failed to parse Office document: " + (error instanceof Error ? error.message : "Unknown error"));
  }
}

async function extractImagesFromOfficeDocument(buffer: Buffer): Promise<string[]> {
  try {
    const zip = await JSZip.loadAsync(buffer);
    const images: string[] = [];
    const imageExtensions = ['.png', '.jpg', '.jpeg', '.gif', '.bmp', '.tiff', '.emf', '.wmf'];
    const maxImages = 10;
    const maxImageSizeKB = 500;

    const mediaFolders = [
      'word/media/',
      'ppt/media/',
      'xl/media/',
      'docProps/thumbnail',
    ];

    const imageFiles: { path: string; size: number }[] = [];

    zip.forEach((relativePath, file) => {
      if (file.dir) return;

      const isInMediaFolder = mediaFolders.some(folder => relativePath.toLowerCase().includes(folder.toLowerCase()));
      const hasImageExtension = imageExtensions.some(ext => relativePath.toLowerCase().endsWith(ext));

      if (isInMediaFolder || hasImageExtension) {
        imageFiles.push({ path: relativePath, size: 0 });
      }
    });

    const sortedFiles = imageFiles.slice(0, maxImages * 2);

    for (const fileInfo of sortedFiles) {
      if (images.length >= maxImages) break;

      try {
        const file = zip.file(fileInfo.path);
        if (!file) continue;

        const data = await file.async('base64');
        const sizeKB = (data.length * 0.75) / 1024;

        if (sizeKB > maxImageSizeKB) {
          console.log(`Skipping large image: ${fileInfo.path} (${sizeKB.toFixed(1)}KB)`);
          continue;
        }

        const ext = fileInfo.path.toLowerCase().split('.').pop() || 'png';
        const mimeType = ext === 'jpg' || ext === 'jpeg' ? 'image/jpeg' : 
                         ext === 'png' ? 'image/png' : 
                         ext === 'gif' ? 'image/gif' : 'image/png';

        const dataUrl = `data:${mimeType};base64,${data}`;
        images.push(dataUrl);
        console.log(`Extracted image: ${fileInfo.path} (${sizeKB.toFixed(1)}KB)`);
      } catch (err) {
        console.warn(`Failed to extract image ${fileInfo.path}:`, err);
      }
    }

    console.log(`Total images extracted: ${images.length}`);
    return images;
  } catch (error) {
    console.error("Error extracting images from Office document:", error);
    return [];
  }
}

function isOfficeDocument(fileType: string): boolean {
  return (
    fileType.includes("wordprocessingml") ||
    fileType.includes("presentationml") ||
    fileType.includes("spreadsheetml") ||
    fileType === "application/msword" ||
    fileType === "application/vnd.ms-powerpoint" ||
    fileType === "application/vnd.ms-excel"
  );
}

export async function processJob(id: string) {
  const job = jobs.get(id);
  const buffer = jobBuffers.get(id);

  if (!job || !buffer) {
    return;
  }

  try {
    updateJob(id, { status: "processing", progress: 10, message: "Starting document analysis..." });

    let extractedText = "";
    let documentImages: string[] = [];
    let isOfficeWithImages = false;
    let isImageFile = false;
    const fileType = job.fileType;

    if (fileType === "application/pdf") {
      updateJob(id, { progress: 20, message: "Extracting text from PDF..." });
      extractedText = await extractTextFromPDF(buffer);
    } else if (fileType.startsWith("image/")) {
      isImageFile = true;
      updateJob(id, { progress: 20, message: "Processing image for visual analysis..." });
      // Skip OCR for images - AI will analyze the image directly
      extractedText = "";
    } else if (isOfficeDocument(fileType)) {
      updateJob(id, { progress: 15, message: "Extracting text from document..." });
      extractedText = await extractTextFromOfficeDocument(buffer);

      updateJob(id, { progress: 40, message: "Scanning for images and graphics..." });
      documentImages = await extractImagesFromOfficeDocument(buffer);

      if (documentImages.length > 0) {
        isOfficeWithImages = true;
        console.log(`Office document has ${documentImages.length} images - will use vision processing`);
      }
    }

    updateJob(id, { progress: 80, message: "Finalizing..." });

    if (isOfficeWithImages) {
      updateJob(id, {
        status: "completed",
        progress: 100,
        message: "Document ready for visual analysis!",
        text: extractedText,
        isOfficeWithImages: true,
        documentImages: documentImages,
      });
    } else if (isImageFile) {
      updateJob(id, {
        status: "completed",
        progress: 100,
        message: "Image ready for visual analysis!",
        text: "",
        isOfficeWithImages: false,
        isImageOnly: true,
      });
    } else {
      if (!extractedText || extractedText.length < 50) {
        throw new Error("Not enough text could be extracted from this document. Please try a different file with more readable content.");
      }

      updateJob(id, {
        status: "completed",
        progress: 100,
        message: "Extraction complete!",
        text: extractedText,
        isOfficeWithImages: false,
      });
    }
    cleanupBuffer(id);
  } catch (error) {
    console.error("Job processing error:", error);
    updateJob(id, {
      status: "error",
      progress: 0,
      message: "Extraction failed",
      error: error instanceof Error ? error.message : "Failed to extract text",
    });
    cleanupBuffer(id);
  }
}

